const payload = $json.body ?? $json;
const message = String(payload.message ?? '').trim();
const channel = String(payload.channel ?? 'unknown');
const lower = message.toLowerCase();
let reply = '자동화 요청을 접수했습니다. 세부 workflow 연결 후 결과를 전달하겠습니다.';
let action = 'generic';
if (lower.includes('일정') || lower.includes('calendar') || lower.includes('캘린더')) {
  action = 'calendar-summary';
  reply = '캘린더 자동화 경로로 요청을 접수했습니다. 실제 Google Calendar 자격 증명이 연결되면 오늘 일정을 조회하도록 확장할 수 있습니다.';
} else if (lower.includes('메일') || lower.includes('email') || lower.includes('gmail')) {
  action = 'gmail-summary';
  reply = '메일 자동화 경로로 요청을 접수했습니다. 실제 Gmail 자격 증명이 연결되면 최근 메일 요약을 반환하도록 확장할 수 있습니다.';
} else if (lower.includes('노션') || lower.includes('notion')) {
  action = 'notion-update';
  reply = '노션 자동화 경로로 요청을 접수했습니다. 실제 Notion 자격 증명이 연결되면 페이지 조회나 저장 작업으로 확장할 수 있습니다.';
}
return [{ json: { reply, action, channel, session_id: payload.session_id ?? null, user_id: payload.user_id ?? null } }];
